import 'package:flutter/material.dart';

class DemoStatefulWidget extends StatefulWidget {
  @override
  State<StatefulWidget> createState() {
    // TODO: implement createState
    return Trangthai_DemoStateWidge();
  }
}

class Trangthai_DemoStateWidge extends State<DemoStatefulWidget> {
  void thaydoiDiem() {
    double a = double.tryParse(txt1.text) ?? 0;
    setState(() {
      diem = a;
    });
  }

  bool? namnu = false;
  double diem = 0;
  TextEditingController txt1 = TextEditingController();

  @override
  Widget build(BuildContext context) {
    // TODO: implement build
    return Scaffold(
      appBar: AppBar(title: Text("Demo Widget có trạng thái")),
      body: Column(children: [
        Checkbox(
          isError: true,
          tristate: true,
          value: namnu,
          onChanged: (bool? value) {
            setState(() {
              namnu = value;
            });
          },
        ),
        (namnu == true)
            ? Container(
                width: 100,
                child: Image.network(
                    "https://cdn-icons-png.flaticon.com/512/2042/2042895.png"),
              )
            : Container(
                width: 100,
                child: Image.network(
                    "https://as1.ftcdn.net/v2/jpg/01/54/63/22/1000_F_154632264_mzeBfVl6QdkDLhVKWOAkTZvTIgICwfwZ.jpg"),
              ),
        SizedBox(height: 10),
        TextField(
          controller: txt1,
          onChanged: (value) {
            thaydoiDiem();
          },
          decoration: InputDecoration(hintText: "Nhập điểm"),
          style: TextStyle(fontSize: 20),
        ),
        (diem >= 7)
            ? Image.network(
                "data:image/jpeg;base64,",
                width: 200,
              )
            : Image.network(
                "data:image/jpeg;base64,",
                width: 200,
              )
      ]),
    );
  }
}
